            <h1 class="article-title">Unique Gator Trophy Serves More Than One Purpose</h1>

            <div class="social-share">
                <div>
                    <small style="text-transform: uppercase; font-weight: bold; color: #333; border-top: 1px dotted #ccc; display: inline-block; padding-top: 5px;">Admin</small>
                </div>
